-- ============================================================
-- 006_payroll.sql
-- Payslips, payroll runs, adjustments, final pay, pay schedule
-- ============================================================

-- Pay Schedule Config (singleton-ish — one active row)
CREATE TABLE IF NOT EXISTS public.pay_schedule_config (
    id                          text PRIMARY KEY DEFAULT 'default',
    default_frequency           text NOT NULL DEFAULT 'semi_monthly'
                                CHECK (default_frequency IN ('monthly','semi_monthly','bi_weekly','weekly')),
    semi_monthly_first_cutoff   integer NOT NULL DEFAULT 15,
    semi_monthly_first_pay_day  integer NOT NULL DEFAULT 20,
    semi_monthly_second_pay_day integer NOT NULL DEFAULT 5,
    monthly_pay_day             integer NOT NULL DEFAULT 30,
    bi_weekly_start_date        date,
    weekly_pay_day              integer NOT NULL DEFAULT 5,
    deduct_gov_from             text NOT NULL DEFAULT 'second'
                                CHECK (deduct_gov_from IN ('first','second','both')),
    updated_at                  timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.pay_schedule_config ENABLE ROW LEVEL SECURITY;

DROP TRIGGER IF EXISTS set_pay_schedule_config_updated_at ON public.pay_schedule_config;
CREATE TRIGGER set_pay_schedule_config_updated_at
    BEFORE UPDATE ON public.pay_schedule_config
    FOR EACH ROW
    EXECUTE FUNCTION public.handle_updated_at();

-- Payroll Runs
CREATE TABLE IF NOT EXISTS public.payroll_runs (
    id                text PRIMARY KEY,
    period_label      text NOT NULL,
    created_at        timestamptz NOT NULL DEFAULT now(),
    status            text NOT NULL DEFAULT 'draft'
                      CHECK (status IN ('draft','validated','locked','published','paid')),
    locked            boolean NOT NULL DEFAULT false,
    locked_at         timestamptz,
    published_at      timestamptz,
    paid_at           timestamptz,
    payslip_ids       text[] NOT NULL DEFAULT '{}',
    policy_snapshot   jsonb,
    run_type          text DEFAULT 'regular'
                      CHECK (run_type IN ('regular','adjustment','13th_month','final_pay'))
);

CREATE INDEX IF NOT EXISTS idx_payroll_runs_status ON public.payroll_runs(status);

ALTER TABLE public.payroll_runs ENABLE ROW LEVEL SECURITY;

-- Payslips
CREATE TABLE IF NOT EXISTS public.payslips (
    id                      text PRIMARY KEY,
    employee_id             text NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
    period_start            date NOT NULL,
    period_end              date NOT NULL,
    pay_frequency           text CHECK (pay_frequency IN ('monthly','semi_monthly','bi_weekly','weekly')),
    gross_pay               numeric NOT NULL DEFAULT 0,
    allowances              numeric NOT NULL DEFAULT 0,
    sss_deduction           numeric NOT NULL DEFAULT 0,
    philhealth_deduction    numeric NOT NULL DEFAULT 0,
    pagibig_deduction       numeric NOT NULL DEFAULT 0,
    tax_deduction           numeric NOT NULL DEFAULT 0,
    other_deductions        numeric NOT NULL DEFAULT 0,
    loan_deduction          numeric NOT NULL DEFAULT 0,
    holiday_pay             numeric DEFAULT 0,
    net_pay                 numeric NOT NULL DEFAULT 0,
    issued_at               date NOT NULL,
    status                  text NOT NULL DEFAULT 'issued'
                            CHECK (status IN ('issued','confirmed','published','paid','acknowledged')),
    confirmed_at            timestamptz,
    published_at            timestamptz,
    paid_at                 timestamptz,
    payment_method          text,
    bank_reference_id       text,
    payroll_batch_id        text,
    pdf_hash                text,
    notes                   text,
    signed_at               timestamptz,
    signature_data_url      text,
    ack_text_version        text,
    adjustment_ref          text,
    acknowledged_at         timestamptz,
    acknowledged_by         text,
    paid_confirmed_by       text,
    paid_confirmed_at       timestamptz
);

CREATE INDEX IF NOT EXISTS idx_payslips_employee ON public.payslips(employee_id);
CREATE INDEX IF NOT EXISTS idx_payslips_status ON public.payslips(status);
CREATE INDEX IF NOT EXISTS idx_payslips_period ON public.payslips(period_start, period_end);

ALTER TABLE public.payslips ENABLE ROW LEVEL SECURITY;

-- Payroll Adjustments
CREATE TABLE IF NOT EXISTS public.payroll_adjustments (
    id                  text PRIMARY KEY,
    payroll_run_id      text NOT NULL,
    employee_id         text NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
    adjustment_type     text NOT NULL CHECK (adjustment_type IN ('earnings','deduction','net_correction','statutory_correction')),
    reference_payslip_id text NOT NULL,
    amount              numeric NOT NULL,
    reason              text NOT NULL,
    created_by          text NOT NULL,
    created_at          timestamptz NOT NULL DEFAULT now(),
    approved_by         text,
    approved_at         timestamptz,
    applied_run_id      text,
    status              text NOT NULL DEFAULT 'pending'
                        CHECK (status IN ('pending','approved','applied','rejected'))
);

CREATE INDEX IF NOT EXISTS idx_adj_employee ON public.payroll_adjustments(employee_id);
CREATE INDEX IF NOT EXISTS idx_adj_run ON public.payroll_adjustments(payroll_run_id);

ALTER TABLE public.payroll_adjustments ENABLE ROW LEVEL SECURITY;

-- Final Pay Computations
CREATE TABLE IF NOT EXISTS public.final_pay_computations (
    id                      text PRIMARY KEY,
    employee_id             text NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
    resigned_at             date NOT NULL,
    pro_rated_salary        numeric NOT NULL DEFAULT 0,
    unpaid_ot               numeric NOT NULL DEFAULT 0,
    leave_payout            numeric NOT NULL DEFAULT 0,
    remaining_loan_balance  numeric NOT NULL DEFAULT 0,
    gross_final_pay         numeric NOT NULL DEFAULT 0,
    deductions              numeric NOT NULL DEFAULT 0,
    net_final_pay           numeric NOT NULL DEFAULT 0,
    status                  text NOT NULL DEFAULT 'draft'
                            CHECK (status IN ('draft','validated','locked','published','paid')),
    created_at              timestamptz NOT NULL DEFAULT now(),
    payslip_id              text
);

CREATE INDEX IF NOT EXISTS idx_final_pay_employee ON public.final_pay_computations(employee_id);

ALTER TABLE public.final_pay_computations ENABLE ROW LEVEL SECURITY;


-- ----------------------------------------------------------------------------
-- SOURCE: 016_fix_loans_timestamp.sql
-- ----------------------------------------------------------------------------
-- ============================================================
-- 016_fix_loans_timestamp.sql
-- Fix loans.created_at: date → timestamptz (align with all other tables)
-- ============================================================

DO $$
BEGIN
    -- Only ALTER if the column type is 'date' (not already timestamptz)
    IF EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_schema = 'public'
          AND table_name   = 'loans'
          AND column_name  = 'created_at'
          AND data_type    = 'date'
    ) THEN
        ALTER TABLE public.loans
            ALTER COLUMN created_at TYPE timestamptz USING created_at::timestamptz,
            ALTER COLUMN created_at SET DEFAULT now();
    END IF;
END $$;


-- ----------------------------------------------------------------------------
-- SOURCE: 024_finance_rls_fixes.sql
-- ----------------------------------------------------------------------------
-- ============================================================
-- 024_finance_rls_fixes.sql
-- Grant finance and payroll_admin appropriate read/write access:
--   • employees  : read all + manage (salary edits, payroll processing)
--   • leave_balances  : read-only (payroll deduction calculations)
--   • attendance_logs : read-only (payroll hours calculations)
-- Fix channel_messages UPDATE for employees (read-receipt / own-message edits)
-- The write-through layer in sync.service.ts is separately gated
-- to prevent finance from writing leave_balances/attendance_logs.
-- ============================================================

-- ─── Employees: expand read to finance / payroll_admin / auditor ──────────
DROP POLICY IF EXISTS employees_read_admin ON public.employees;
CREATE POLICY employees_read_admin ON public.employees
    FOR SELECT USING (
        public.get_user_role() IN ('admin', 'hr', 'finance', 'payroll_admin', 'auditor')
    );

-- Employees: expand manage (INSERT/UPDATE/DELETE) to finance / payroll_admin
-- Finance legitimately edits salary fields and the finance-view already allows it.
DROP POLICY IF EXISTS employees_manage_admin ON public.employees;
CREATE POLICY employees_manage_admin ON public.employees
    FOR ALL USING (
        public.get_user_role() IN ('admin', 'hr', 'finance', 'payroll_admin')
    );

-- ─── Leave balances: finance / payroll_admin can read (deduction calc) ────
-- Leave them out of lb_manage so they cannot create or modify balances.
DROP POLICY IF EXISTS lb_read_admin ON public.leave_balances;
CREATE POLICY lb_read_admin ON public.leave_balances
    FOR SELECT USING (
        public.get_user_role() IN ('admin', 'hr', 'finance', 'payroll_admin', 'auditor')
    );

-- ─── Attendance logs: finance / payroll_admin can read (hours calc) ───────
-- Leave them out of al_manage so they cannot create or modify logs.
DROP POLICY IF EXISTS al_read_admin ON public.attendance_logs;
CREATE POLICY al_read_admin ON public.attendance_logs
    FOR SELECT USING (
        public.get_user_role() IN ('admin', 'hr', 'finance', 'payroll_admin', 'auditor')
    );

-- ─── Channel messages: allow employees to update their own messages ────────
-- NOTE: channel_messages is created in 08_tasks_projects_messaging.sql.
-- These policies have been moved to 15_rls_policies.sql to avoid forward references.

-- ─── Face enrollments: allow employees to self-enroll ─────────────────────
-- Existing policies fe_insert/fe_update are admin-only; add employee self-service.
-- Employees can only insert/update their OWN enrollment row.
DROP POLICY IF EXISTS fe_self_insert ON public.face_enrollments;
CREATE POLICY fe_self_insert ON public.face_enrollments
    FOR INSERT WITH CHECK (
        public.is_own_employee(employee_id) OR public.is_admin_or_hr()
    );

DROP POLICY IF EXISTS fe_self_update ON public.face_enrollments;
CREATE POLICY fe_self_update ON public.face_enrollments
    FOR UPDATE USING (
        public.is_own_employee(employee_id) OR public.is_admin_or_hr()
    )
    WITH CHECK (
        public.is_own_employee(employee_id) OR public.is_admin_or_hr()
    );

-- Drop the old admin-only policies so they don't conflict
DROP POLICY IF EXISTS fe_insert ON public.face_enrollments;
DROP POLICY IF EXISTS fe_update ON public.face_enrollments;


-- ----------------------------------------------------------------------------
-- SOURCE: 028_payroll_run_payslips_junction.sql
-- ----------------------------------------------------------------------------
-- ============================================================
-- 028_payroll_run_payslips_junction.sql
-- Replace payroll_runs.payslip_ids text[] with proper junction table.
-- Maintains backward compatibility during transition.
-- ============================================================

-- ─── Junction table ──────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.payroll_run_payslips (
    run_id      text NOT NULL REFERENCES public.payroll_runs(id) ON DELETE CASCADE,
    payslip_id  text NOT NULL REFERENCES public.payslips(id) ON DELETE CASCADE,
    added_at    timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (run_id, payslip_id)
);

CREATE INDEX IF NOT EXISTS idx_prp_payslip ON public.payroll_run_payslips(payslip_id);

ALTER TABLE public.payroll_run_payslips ENABLE ROW LEVEL SECURITY;

-- RLS: match parent table (payroll_runs) access pattern
CREATE POLICY "payroll_run_payslips_read"
    ON public.payroll_run_payslips
    FOR SELECT
    TO authenticated
    USING (
        public.get_user_role() IN ('admin', 'finance', 'payroll_admin', 'auditor')
    );

CREATE POLICY "payroll_run_payslips_write"
    ON public.payroll_run_payslips
    FOR ALL
    TO authenticated
    USING (
        public.get_user_role() IN ('admin', 'finance', 'payroll_admin')
    )
    WITH CHECK (
        public.get_user_role() IN ('admin', 'finance', 'payroll_admin')
    );

-- ─── Migrate existing data ───────────────────────────────────
-- Move payslip_ids array entries into the junction table.

INSERT INTO public.payroll_run_payslips (run_id, payslip_id)
SELECT pr.id, unnest(pr.payslip_ids)
FROM public.payroll_runs pr
WHERE array_length(pr.payslip_ids, 1) > 0
ON CONFLICT DO NOTHING;

-- ─── Keep the old column but mark it deprecated ──────────────
-- The column will be dropped in a future migration after all code
-- has been migrated to use the junction table.
COMMENT ON COLUMN public.payroll_runs.payslip_ids
    IS 'DEPRECATED — use payroll_run_payslips junction table. Will be removed in a future migration.';


-- ----------------------------------------------------------------------------
-- SOURCE: 036_deduction_overrides.sql
-- ----------------------------------------------------------------------------
-- ═══════════════════════════════════════════════════════════════
-- Migration 036: Government Deduction Overrides (Philippine Standard)
-- 
-- Stores per-employee override settings for SSS, PhilHealth,
-- Pag-IBIG, and BIR withholding tax. Supports: auto (standard PH
-- calculation), exempt (₱0), percentage (% of gross), or fixed (₱).
-- ═══════════════════════════════════════════════════════════════

-- Per-employee, per-deduction-type overrides
CREATE TABLE IF NOT EXISTS public.deduction_overrides (
    id text NOT NULL DEFAULT ('DO-' || gen_random_uuid()::text),
    employee_id text NOT NULL,
    deduction_type text NOT NULL CHECK (deduction_type IN ('sss', 'philhealth', 'pagibig', 'bir')),
    mode text NOT NULL DEFAULT 'auto' CHECK (mode IN ('auto', 'exempt', 'percentage', 'fixed')),
    percentage numeric CHECK (percentage >= 0 AND percentage <= 100),
    fixed_amount numeric CHECK (fixed_amount >= 0),
    notes text,
    created_at timestamptz NOT NULL DEFAULT now(),
    updated_at timestamptz NOT NULL DEFAULT now(),
    updated_by text,
    CONSTRAINT deduction_overrides_pkey PRIMARY KEY (id),
    CONSTRAINT deduction_overrides_employee_id_fkey FOREIGN KEY (employee_id) REFERENCES public.employees(id) ON DELETE CASCADE,
    CONSTRAINT deduction_overrides_unique UNIQUE (employee_id, deduction_type)
);

-- Global default overrides (company-wide; employee_id = 'global')
-- e.g., "All employees SSS at 4.5%" — per-employee overrides take precedence
CREATE TABLE IF NOT EXISTS public.deduction_global_defaults (
    id text NOT NULL DEFAULT ('DGD-' || gen_random_uuid()::text),
    deduction_type text NOT NULL CHECK (deduction_type IN ('sss', 'philhealth', 'pagibig', 'bir')),
    enabled boolean NOT NULL DEFAULT true,
    mode text NOT NULL DEFAULT 'auto' CHECK (mode IN ('auto', 'exempt', 'percentage', 'fixed')),
    percentage numeric CHECK (percentage >= 0 AND percentage <= 100),
    fixed_amount numeric CHECK (fixed_amount >= 0),
    notes text,
    updated_at timestamptz NOT NULL DEFAULT now(),
    updated_by text,
    CONSTRAINT deduction_global_defaults_pkey PRIMARY KEY (id),
    CONSTRAINT deduction_global_defaults_unique UNIQUE (deduction_type)
);

-- Seed global defaults (all auto by default)
INSERT INTO public.deduction_global_defaults (id, deduction_type, enabled, mode, notes)
VALUES
    ('DGD-SSS',   'sss',        true, 'auto', 'SSS 2026 table — RA 11199'),
    ('DGD-PH',    'philhealth', true, 'auto', 'PhilHealth 5% — RA 11223 UHC Act'),
    ('DGD-PI',    'pagibig',    true, 'auto', 'Pag-IBIG ₱100 cap — RA 9679'),
    ('DGD-BIR',   'bir',        true, 'auto', 'BIR TRAIN Law — RA 10963')
ON CONFLICT (deduction_type) DO NOTHING;

-- Indexes
CREATE INDEX IF NOT EXISTS idx_deduction_overrides_employee ON public.deduction_overrides(employee_id);
CREATE INDEX IF NOT EXISTS idx_deduction_overrides_type ON public.deduction_overrides(deduction_type);

-- RLS
ALTER TABLE public.deduction_overrides ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.deduction_global_defaults ENABLE ROW LEVEL SECURITY;

-- Admin/HR/Finance/Payroll Admin can manage overrides
CREATE POLICY "admin_manage_deduction_overrides" ON public.deduction_overrides
    FOR ALL
    USING (
        EXISTS (
            SELECT 1 FROM public.employees e
            WHERE e.profile_id = auth.uid()
            AND e.role IN ('admin', 'hr', 'finance', 'payroll_admin')
        )
    );

CREATE POLICY "admin_manage_deduction_global_defaults" ON public.deduction_global_defaults
    FOR ALL
    USING (
        EXISTS (
            SELECT 1 FROM public.employees e
            WHERE e.profile_id = auth.uid()
            AND e.role IN ('admin', 'hr', 'finance', 'payroll_admin')
        )
    );

-- Employees can read their own overrides
CREATE POLICY "employee_read_own_overrides" ON public.deduction_overrides
    FOR SELECT
    USING (
        employee_id IN (
            SELECT id FROM public.employees WHERE profile_id = auth.uid()
        )
    );


