-- Admin/HR/Finance/Payroll Admin: full CRUD
CREATE POLICY deduction_global_defaults_admin_all
    ON public.deduction_global_defaults
    FOR ALL
    USING (
        public.get_user_role() IN ('admin', 'hr', 'finance', 'payroll_admin')
    )
    WITH CHECK (
        public.get_user_role() IN ('admin', 'hr', 'finance', 'payroll_admin')
